parameters.inputSchema:
{
  "type": "array",
  "items": {
    "type": "object",
    "additionalProperties": false,
    "required": [
      "symbol",
      "action",
      "priority",
      "confidence",
      "horizonDays",
      "targetWeightPct",
      "targetQty",
      "rationale",
      "entryPlan",
      "riskPlan",
      "dependencies",
      "nextReviewDays"
    ],
    "properties": {
      "symbol": {
        "type": "string"
      },
      "assetClass": {
        "type": [
          "string",
          "null"
        ],
        "enum": [
          "EQUITY",
          "CRYPTO",
          "FX",
          null
        ]
      },
      "symbol_internal": {
        "type": [
          "string",
          "null"
        ]
      },
      "symbol_yahoo": {
        "type": [
          "string",
          "null"
        ]
      },
      "action": {
        "type": "string",
        "enum": [
          "OPEN",
          "INCREASE",
          "DECREASE",
          "CLOSE",
          "HOLD",
          "WATCH",
          "PROPOSE_OPEN",
          "PROPOSE_CLOSE"
        ]
      },
      "priority": {
        "type": "integer"
      },
      "confidence": {
        "type": [
          "integer",
          "null"
        ]
      },
      "horizonDays": {
        "type": [
          "integer",
          "null"
        ]
      },
      "targetWeightPct": {
        "type": [
          "number",
          "null"
        ]
      },
      "targetQty": {
        "type": [
          "number",
          "null"
        ]
      },
      "rationale": {
        "type": "string"
      },
      "entryPlan": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "orderType",
          "limitPrice",
          "timeInForce"
        ],
        "properties": {
          "orderType": {
            "type": [
              "string",
              "null"
            ]
          },
          "limitPrice": {
            "type": [
              "number",
              "null"
            ]
          },
          "timeInForce": {
            "type": [
              "string",
              "null"
            ]
          }
        }
      },
      "riskPlan": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "stopLossPct",
          "takeProfitPct",
          "maxLossEUR"
        ],
        "properties": {
          "stopLossPct": {
            "type": [
              "number",
              "null"
            ]
          },
          "takeProfitPct": {
            "type": [
              "number",
              "null"
            ]
          },
          "maxLossEUR": {
            "type": [
              "number",
              "null"
            ]
          }
        }
      },
      "dependencies": {
        "oneOf": [
          {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "needPrice",
              "needNote",
              "needNews",
              "needTechnical",
              "needConsensus"
            ],
            "properties": {
              "needPrice": {
                "type": "boolean"
              },
              "needNote": {
                "type": "boolean"
              },
              "needNews": {
                "type": "boolean"
              },
              "needTechnical": {
                "type": "boolean"
              },
              "needConsensus": {
                "type": "boolean"
              }
            }
          },
          {
            "type": "array",
            "items": {
              "type": "string"
            }
          }
        ]
      },
      "execution_required": {
        "type": [
          "boolean",
          "null"
        ]
      },
      "needs_risk_approval": {
        "type": [
          "boolean",
          "null"
        ]
      },
      "proposed_position": {
        "type": [
          "object",
          "null"
        ],
        "additionalProperties": false,
        "properties": {
          "direction": {
            "type": [
              "string",
              "null"
            ],
            "enum": [
              "LONG",
              "SHORT",
              "NEUTRAL",
              null
            ]
          },
          "conviction": {
            "type": [
              "number",
              "null"
            ]
          }
        }
      },
      "nextReviewDays": {
        "type": "integer"
      }
    }
  }
}
